namespace sv_61a78e7f2caf47589b273a312a3cd485.Services;

/// <summary>
/// Per-circuit state that tracks the currently selected warehouse.
/// Registered as Scoped so each SignalR circuit (i.e. each browser tab) gets its own instance.
/// </summary>
public sealed class WarehouseState
{
    public static readonly IReadOnlyDictionary<string, string> Warehouses =
        new Dictionary<string, string>
        {
            ["WH-001"] = "Warehouse A – Downtown",
            ["WH-002"] = "Warehouse B – Airport",
            ["WH-003"] = "Warehouse C – Harbor",
        };

    public string CurrentWarehouseId { get; private set; } = "WH-001";

    public string CurrentWarehouseName =>
        Warehouses.TryGetValue(CurrentWarehouseId, out var name) ? name : CurrentWarehouseId;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (warehouseId == CurrentWarehouseId) return;
        CurrentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_61a78e7f2caf47589b273a312a3cd485.Services;

/// <summary>
/// Simulates a database query returning the number of items below minimum stock levels.
/// </summary>
public sealed class InventoryAlertService
{
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate a database call with a random count between 0 and 15.
        return Task.FromResult(Random.Shared.Next(0, 16));
    }
}

@using sv_61a78e7f2caf47589b273a312a3cd485.Services
@inject WarehouseState Warehouse
@implements IDisposable

<div class="d-flex align-items-center">
    <label class="me-2 mb-0 text-nowrap fw-semibold" for="warehouseSelect">Warehouse:</label>
    <select id="warehouseSelect"
            class="form-select form-select-sm"
            style="min-width: 220px;"
            value="@Warehouse.CurrentWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseState.Warehouses)
        {
            <option value="@wh.Key">@wh.Value</option>
        }
    </select>
</div>

@code {
    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var id = e.Value?.ToString();
        if (!string.IsNullOrEmpty(id))
        {
            Warehouse.SetWarehouse(id);
        }
    }

    protected override void OnInitialized()
    {
        Warehouse.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        Warehouse.OnChange -= StateHasChanged;
    }
}

@using sv_61a78e7f2caf47589b273a312a3cd485.Services
@inject WarehouseState Warehouse
@inject InventoryAlertService AlertService
@implements IDisposable

@if (_lowStockCount.HasValue)
{
    <span class="badge rounded-pill @(_lowStockCount.Value > 0 ? "bg-danger" : "bg-success") ms-2"
          title="@_lowStockCount.Value low-stock items">
        @_lowStockCount.Value
    </span>
}

@code {
    private int? _lowStockCount;
    private CancellationTokenSource? _cts;

    protected override async Task OnInitializedAsync()
    {
        Warehouse.OnChange += OnWarehouseChanged;
        await RefreshAsync();
        StartPolling();
    }

    private void StartPolling()
    {
        _cts?.Cancel();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _ = Task.Run(async () =>
        {
            while (!token.IsCancellationRequested)
            {
                try
                {
                    await Task.Delay(TimeSpan.FromSeconds(10), token);
                    await InvokeAsync(async () =>
                    {
                        await RefreshAsync();
                        StateHasChanged();
                    });
                }
                catch (OperationCanceledException) { break; }
            }
        });
    }

    private async Task RefreshAsync()
    {
        _lowStockCount = await AlertService.GetLowStockCountAsync(Warehouse.CurrentWarehouseId);
    }

    private async void OnWarehouseChanged()
    {
        await InvokeAsync(async () =>
        {
            await RefreshAsync();
            StateHasChanged();
        });
    }

    public void Dispose()
    {
        Warehouse.OnChange -= OnWarehouseChanged;
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@using sv_61a78e7f2caf47589b273a312a3cd485.Services
@inject WarehouseState Warehouse
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard – @Warehouse.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">@Warehouse.CurrentWarehouseName</h5>
        <p class="card-text text-muted">Warehouse ID: @Warehouse.CurrentWarehouseId</p>
    </div>
</div>

<div class="row g-4">
    <div class="col-md-4">
        <div class="card text-bg-@(_lowStockCount > 0 ? "danger" : "success")">
            <div class="card-body text-center">
                <h2 class="display-4">@(_lowStockCount?.ToString() ?? "–")</h2>
                <p class="card-text">Low-Stock Alerts</p>
                <small class="opacity-75">Refreshes every 10 seconds</small>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card text-bg-info">
            <div class="card-body text-center">
                <h2 class="display-4">@_lastChecked</h2>
                <p class="card-text">Last Checked</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card text-bg-secondary">
            <div class="card-body text-center">
                <h2 class="display-4">@_pollCount</h2>
                <p class="card-text">Poll Cycles</p>
            </div>
        </div>
    </div>
</div>

@code {
    private int? _lowStockCount;
    private string _lastChecked = "–";
    private int _pollCount;
    private CancellationTokenSource? _cts;

    protected override async Task OnInitializedAsync()
    {
        Warehouse.OnChange += OnWarehouseChanged;
        await RefreshAsync();
        StartPolling();
    }

    private void StartPolling()
    {
        _cts?.Cancel();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _ = Task.Run(async () =>
        {
            while (!token.IsCancellationRequested)
            {
                try
                {
                    await Task.Delay(TimeSpan.FromSeconds(10), token);
                    await InvokeAsync(async () =>
                    {
                        await RefreshAsync();
                        StateHasChanged();
                    });
                }
                catch (OperationCanceledException) { break; }
            }
        });
    }

    private async Task RefreshAsync()
    {
        _lowStockCount = await AlertService.GetLowStockCountAsync(Warehouse.CurrentWarehouseId);
        _lastChecked = DateTime.Now.ToString("HH:mm:ss");
        _pollCount++;
    }

    private async void OnWarehouseChanged()
    {
        // Restart polling for the new warehouse.
        StartPolling();
        await InvokeAsync(async () =>
        {
            _pollCount = 0;
            await RefreshAsync();
            StateHasChanged();
        });
    }

    public void Dispose()
    {
        Warehouse.OnChange -= OnWarehouseChanged;
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

