@page "/dashboard"
@rendermode InteractiveServer
@using sv_61a78e7f2caf47589b273a312a3cd485.Services
@inject WarehouseState Warehouse
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard – @Warehouse.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">@Warehouse.CurrentWarehouseName</h5>
        <p class="card-text text-muted">Warehouse ID: @Warehouse.CurrentWarehouseId</p>
    </div>
</div>

<div class="row g-4">
    <div class="col-md-4">
        <div class="card text-bg-@(_lowStockCount > 0 ? "danger" : "success")">
            <div class="card-body text-center">
                <h2 class="display-4">@(_lowStockCount?.ToString() ?? "–")</h2>
                <p class="card-text">Low-Stock Alerts</p>
                <small class="opacity-75">Refreshes every 10 seconds</small>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card text-bg-info">
            <div class="card-body text-center">
                <h2 class="display-4">@_lastChecked</h2>
                <p class="card-text">Last Checked</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card text-bg-secondary">
            <div class="card-body text-center">
                <h2 class="display-4">@_pollCount</h2>
                <p class="card-text">Poll Cycles</p>
            </div>
        </div>
    </div>
</div>

@code {
    private int? _lowStockCount;
    private string _lastChecked = "–";
    private int _pollCount;
    private CancellationTokenSource? _cts;

    protected override async Task OnInitializedAsync()
    {
        Warehouse.OnChange += OnWarehouseChanged;
        await RefreshAsync();
        StartPolling();
    }

    private void StartPolling()
    {
        _cts?.Cancel();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _ = Task.Run(async () =>
        {
            while (!token.IsCancellationRequested)
            {
                try
                {
                    await Task.Delay(TimeSpan.FromSeconds(10), token);
                    await InvokeAsync(async () =>
                    {
                        await RefreshAsync();
                        StateHasChanged();
                    });
                }
                catch (OperationCanceledException) { break; }
            }
        });
    }

    private async Task RefreshAsync()
    {
        _lowStockCount = await AlertService.GetLowStockCountAsync(Warehouse.CurrentWarehouseId);
        _lastChecked = DateTime.Now.ToString("HH:mm:ss");
        _pollCount++;
    }

    private async void OnWarehouseChanged()
    {
        // Restart polling for the new warehouse.
        StartPolling();
        await InvokeAsync(async () =>
        {
            _pollCount = 0;
            await RefreshAsync();
            StateHasChanged();
        });
    }

    public void Dispose()
    {
        Warehouse.OnChange -= OnWarehouseChanged;
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

